// // This module designs a 4-bit down counter that decrements its count value on each positive clock edge. The counter resets to zero when the reset (rst) signal is low. When rst is high, the counter will continuously count downwards from its current value, wrapping around back to zero after reaching 0.
module top_module(
    input clk,
    input rst,
    output reg [3:0] count
);always @(posedge clk or negedge rst) begin
    if (!rst) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
